 1	import * as React from 'react';
 2	import { useCustomTranslation } from '@odf/shared';
 3	import { BlueInfoCircleIcon } from '@odf/shared/status';
 4	import { LazyNameValueEditor } from '@odf/shared/utils/NameValueEditor';
 5	import * as _ from 'lodash-es';
 6	import { FormGroup, Divider, Text } from '@patternfly/react-core';
 7	import { TagIcon } from '@patternfly/react-icons';
 8	import {
 9	  MAX_TAGS,
10	  TAG_KEY_MAX_LENGTH,
11	  TAG_VALUE_MAX_LENGTH,
12	} from '../../../constants/s3-iam';
13	import { KeyValuePair } from '../../../types/s3-iam';
14	
15	export type AddKeyValuePairsProps = {
16	  pairs: KeyValuePair[];
17	  setPairs: React.Dispatch<React.SetStateAction<KeyValuePair[]>>;
18	};
19	
20	export const AddKeyValuePairs: React.FC<AddKeyValuePairsProps> = ({
21	  pairs,
22	  setPairs,
23	}) => {
24	  const { t } = useCustomTranslation();
25	
26	  // Convert KeyValuePair[] to nameValuePairs format: [name, value, index][]
27	  const nameValuePairs = React.useMemo(() => {
28	    return pairs.map((pair, index) => [pair.Key, pair.Value, index]);
29	  }, [pairs]);
30	
31	  const handleUpdateParentData = React.useCallback(
32	    (data: { nameValuePairs: any[] }) => {
33	      // Use Map for semantic key-value processing (preserves insertion order)
34	      const pairsMap = new Map<string, string>();
35	      data.nameValuePairs.forEach(([key, value]) => {
36	        pairsMap.set(key || '', value || '');
37	      });
38	
39	      // Convert Map entries to KeyValuePair[] format (order is preserved)
40	      const updatedPairs: KeyValuePair[] = Array.from(pairsMap.entries()).map(
41	        ([Key, Value]) => ({ Key, Value })
42	      );
43	      setPairs(updatedPairs);
44	    },
45	    [setPairs]
46	  );
47	
48	  const removeAllPairs = React.useCallback(() => {
49	    setPairs([]);
50	  }, [setPairs]);
51	
52	  // Count valid tags (non-empty keys)
53	  const numberOfTagsAdded = pairs?.length;
54	  const remainingTags = MAX_TAGS - numberOfTagsAdded;
55	
56	  return (
57	    <div>
58	      <FormGroup
59	        label={t('Tags')}
60	        className={_.isEmpty(pairs) ? 'pf-v6-u-mt-md' : 'pf-v6-u-mt-md'}
61	      >
62	        <Text component="p" className="pf-v6-u-mb-sm">
63	          <BlueInfoCircleIcon className="pf-v6-u-mr-sm" />
64	          {t(`You can add ${remainingTags} more tags`)}
65	        </Text>
66	
67	        {_.isEmpty(pairs) && (
68	          <div className="text-muted pf-v6-u-mb-sm">
69	            {t('No tags are attached to this user.')}
70	          </div>
71	        )}
72	        <LazyNameValueEditor
73	          nameValuePairs={nameValuePairs}
74	          updateParentData={handleUpdateParentData}
75	          nameValueId={1}
76	          onLastItemRemoved={removeAllPairs}
77	          addString={t('Add tag')}
78	          valueString={t('Value (optional)')}
79	          hideHeaderWhenNoItems={true}
80	          IconComponent={TagIcon}
81	          nameMaxLength={TAG_KEY_MAX_LENGTH}
82	          valueMaxLength={TAG_VALUE_MAX_LENGTH}
83	          allowSorting={false}
84	          readOnly={false}
85	          toolTip={t('Remove tag')}
86	          nameString={t('Key')}
87	          configMaps={{}}
88	          secrets={{}}
89	          addConfigMapSecret={false}
90	          alwaysAllowRemove={true}
91	        />
92	      </FormGroup>
93	      <Divider className="pf-v6-u-mt-2xl" />
94	    </div>
95	  );
96	};

